def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 7:
            for a in range(7, 3, -1):
                for b in range(2, a + 5):
                    priority += ((ratio - a) ** 6) / (a * b * 0.85 + 1) * np.sin(ratio * b / (a + 2))
                for c in range(1, 4):
                    priority += np.tanh(np.cos(ratio * c * a)) * np.exp(-c * 0.3)
            priority += (np.sinh(ratio - 7) * np.cos(ratio * 1.3)) ** 1.7
            if bin_cap < item * 0.5:
                priority += np.log1p(item ** 3 / (bin_cap + 0.1)) * 7
        elif 4 < ratio <= 7:
            acc = 0
            for p in range(1, int(np.ceil(ratio)) + 4):
                for q in range(1, p + 3):
                    term = ((ratio - p) ** 4) * np.cos(ratio * p * 1.1) / (q + 0.3)
                    acc += np.tanh(term) * 1.3
            priority = acc + np.log(ratio) * 12 - np.tanh(ratio - 4) * 3
            if bin_cap > item * 3:
                priority -= np.exp(-ratio) * 5
        elif 2 <= ratio <= 4:
            s = 0
            for r in range(1, 15):
                s += ((ratio - 2) ** r) / (r * 1.5) * np.sin(r * ratio * 1.2)
            priority = (s * np.cos(6 * ratio)) - np.log(ratio) * 8 + np.tanh(3 * (4 - ratio)) * 2
            for z in range(1, 6):
                priority += np.sin(z * ratio * i * 0.9) * (ratio - 2) ** z / z
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 12):
                s += ((2 - ratio) ** n) / (n ** 2 + 1) * np.cos(n * ratio * 1.5)
            if bin_cap < item * 0.95:
                penalty = np.sqrt(item / (bin_cap + 0.2)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for m in range(1, 7):
                priority += np.sin(m * ratio * i) * ((ratio - 1) ** m) / (m + 0.5)
        elif 0.4 <= ratio < 1:
            s = 0
            for n in range(1, 20):
                s += ((1 - ratio) ** n) / (n * 3.5)
            priority = s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.5
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.5) * 0.8
        elif 0.15 <= ratio < 0.4:
            s = 0
            for k in range(1, 15):
                s += ((0.4 - ratio) ** k) / (k * 2.5) * np.cos(k * ratio * 3)
            priority = s + 1.5 / (bin_cap + 5)
            if int(item * 2) % 6 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for m in range(1, 9):
                priority += ((0.4 - ratio) ** m) / (m * 5) * np.cos(item * m * 1.3)
        else:
            s = 0
            for t in range(1, 12):
                s += ((0.15 - ratio) ** t) / (t * 6) * np.sin(t * item * 0.7)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.9) % 6 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for u in range(1, 10):
                priority += ((0.15 - ratio) ** u) / (u * 8) * np.cos(item * u * 0.6)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 3 * bin_cap) * 6.5
        elif bin_cap > item * 3.5:
            priority -= np.exp(-4 * ratio) * 6
        for idx in range(1, 5):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.1) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 0.9) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.8
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.8
        if bin_cap % 2 == 0:
            priority += (np.sin(ratio * bin_cap) * np.cos(item)) * 0.5
        else:
            priority -= (np.cos(ratio * bin_cap) * np.sin(item)) * 0.5
        priorities[i] = priority
    return priorities
